Javascript.validate:
			//cannot be in future: working days only
			var orderDate = Services.getValue(DateOfAEOrder.dataBinding);
			var err = null;

			if( true == isFutureDate(orderDate))
			{	err = ErrorCode.getErrorCode("CaseMan_dateCannotBeInTheFuture_Msg");
			}
			else if( isNonWorkingDate(orderDate))
		    {   err = ErrorCode.getErrorCode("CaseMan_dateNonWorkingDay_Msg"); 
		    }

		    return err;
